// Extracts category, maps to Wayfair URL, and extracts Amazon + Walmart URLs

const input = $input.first().json.chatInput || '';

// Category definitions with Wayfair URL mapping
const categories = [
  { 
    key: 'area_rug', 
    patterns: ['area rug', 'area rugs'],
    wayfairUrl: 'https://www.wayfair.com/rugs/sb0/area-rugs-c215386.html',
    displayName: 'Area Rugs'
  },
  { 
    key: 'outdoor_rug', 
    patterns: ['outdoor rug', 'outdoor rugs', 'patio rug', 'patio rugs'],
    wayfairUrl: 'https://www.wayfair.com/rugs/sb0/outdoor-rugs-c478542.html',
    displayName: 'Outdoor Rugs'
  },
  { 
    key: 'hallway_runner', 
    patterns: ['hallway runner', 'runner rug', 'hall runner', 'runners', 'hallway runners'],
    wayfairUrl: 'https://www.wayfair.com/rugs/sb0/hallway-runners-c416168.html',
    displayName: 'Hallway Runners'
  },
  { 
    key: 'shag_rug', 
    patterns: ['shag rug', 'shag rugs', 'shaggy rug', 'shaggy rugs'],
    wayfairUrl: 'https://www.wayfair.com/rugs/sb1/shag-area-rugs-c215386-a2959~477552.html',
    displayName: 'Shag Rugs'
  }
];

// Detect category from input
const inputLower = input.toLowerCase();
let detectedCategory = null;

for (const cat of categories) {
  for (const pattern of cat.patterns) {
    if (inputLower.includes(pattern)) {
      detectedCategory = cat;
      break;
    }
  }
  if (detectedCategory) break;
}

// Default to area_rug if no category detected
if (!detectedCategory) {
  detectedCategory = categories[0];
  console.log('No category detected, defaulting to area_rug');
}

// Extract Amazon URLs from input
const amazonRegex = /(https?:\/\/(?:www\.)?amazon\.[a-z.]+\/[^\s]+)/gi;
const amazonUrls = input.match(amazonRegex) || [];

// Classify Amazon URLs into products and collections
const amazonProducts = [];
const amazonCollections = [];

amazonUrls.forEach(url => {
  const cleanUrl = url.trim().replace(/,+$/, '');
  if (/\/dp\/|\/gp\/product\//.test(cleanUrl)) {
    amazonProducts.push(cleanUrl);
  } else if (/\/gp\/bestsellers\/|\/s\?|\/b\//.test(cleanUrl)) {
    amazonCollections.push(cleanUrl);
  }
});

// Extract Walmart URLs from input
const walmartRegex = /(https?:\/\/(?:www\.)?walmart\.com\/[^\s]+)/gi;
const walmartUrls = input.match(walmartRegex) || [];

// Classify Walmart URLs into products and collections
const walmartProducts = [];
const walmartCollections = [];

walmartUrls.forEach(url => {
  const cleanUrl = url.trim().replace(/,+$/, '');
  if (/\/ip\//.test(cleanUrl)) {
    walmartProducts.push(cleanUrl);
  } else if (/\/search\?q=|\/browse\//.test(cleanUrl)) {
    walmartCollections.push(cleanUrl);
  }
});

// Validate input - now includes Walmart
const hasValidInput = amazonProducts.length > 0 || amazonCollections.length > 0 || walmartProducts.length > 0 || walmartCollections.length > 0;

console.log(`Category: ${detectedCategory.displayName}`);
console.log(`Wayfair URL: ${detectedCategory.wayfairUrl}`);
console.log(`Amazon Products: ${amazonProducts.length}, Collections: ${amazonCollections.length}`);
console.log(`Walmart Products: ${walmartProducts.length}, Collections: ${walmartCollections.length}`);

return [{
  json: {
    category: detectedCategory.key,
    categoryDisplayName: detectedCategory.displayName,
    wayfairUrl: detectedCategory.wayfairUrl,
    productUrls: amazonProducts,
    collectionUrls: amazonCollections,
