// Parse Walmart Product Data
const inputItems = $input.all();
const allProducts = [];

function extractProductData(html) {
  const product = {
    name: null,
    price: null,
    originalPrice: null,
    sizes: [],
    colors: [],
    description: null,
    productId: null,
    source: 'walmart'
  };

  // Extract Product Name
  const nameMatch = html.match(/<h1[^>]*id="main-title"[^>]*>([^<]+)/i);
  if (nameMatch) product.name = nameMatch[1].trim();

  // Extract Current Price
  const priceMatch = html.match(/<span[^>]*itemprop="price"[^>]*>([^<]+)/i);
  if (priceMatch) product.price = priceMatch[1].trim();

  // Extract Original Price (if on sale)
  const originalPriceMatch = html.match(/Was\s*\$([0-9,.]+)/i);
  if (originalPriceMatch) product.originalPrice = `$${originalPriceMatch[1]}`;

  // Extract Sizes with individual prices
  const sizeMatches = [...html.matchAll(/variant-tile-price-text-([^"]+)"[^>]*>\$([0-9,.]+)/g)];
  sizeMatches.forEach(([, size, price]) => {
    product.sizes.push({ size: size.trim(), price: `$${price}` });
  });

  // Extract Colors
  const colorMatches = [...html.matchAll(/aria-label="([^"]+)"[^>]*role="img"/g)];
  colorMatches.forEach(([, color]) => {
    product.colors.push({ color: color.trim() });
  });

  // Extract Description
  const descStart = html.indexOf('<ul>', html.indexOf('About this item'));
  if (descStart !== -1) {
    const descEnd = html.indexOf('</ul>', descStart);
    if (descEnd !== -1) {
      product.description = html.substring(descStart, descEnd)
        .replace(/<[^>]*>/g, ' ')
        .replace(/\s+/g, ' ')
        .trim();
    }
  }

  // Extract Product ID
  const idMatch = html.match(/\/ip\/[^\/]+\/(\d+)/);
  if (idMatch) product.productId = idMatch[1];

  return product;
}

for (let i = 0; i < inputItems.length; i++) {
  const htmlContent = inputItems[i].json.data;
  if (htmlContent && typeof htmlContent === 'string') {
    const productData = extractProductData(htmlContent);
    productData.scraped_at = new Date().toISOString();
    if (productData.name) {
      allProducts.push({ json: productData });
    }
  }
}

return allProducts.length > 0 ? allProducts : [{ json: { error: 'No products parsed' } }];

