// HTML ASSEMBLER - Combines all sections into final report

const category = $('Input Parser').first().json.categoryDisplayName || 'Rugs';
const scopeHtml = $('Scope Generator').first().json.html || '';
const execSummary = $('Gemini - Executive').first().json.output || '';
const amazonAnalysis = $('Amazon Analysis Generator').first().json.output || '';
const comparison = $('Comparison Generator').first().json.output || '';
const pricingWhitespace = $('Pricing & Whitespace').first().json.output || '';
const recommendations = $('Recommendations').first().json.output || '';
const supplierIdentification = $('Supplier Identification').first().json.output || '';

const fullHtml = `<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0">
  <title>Competitor Analysis Report - ${category}</title>
  <link href="https://fonts.googleapis.com/css2?family=Inter:wght@400;500;600;700&display=swap" rel="stylesheet">
  <style>
      :root {
        --primary: #7C3AED;
        --primary-light: #A78BFA;
        --success: #059669;
        --warning: #D97706;
        --danger: #DC2626;
        --gray-50: #F9FAFB;
        --gray-100: #F3F4F6;
        --gray-200: #E5E7EB;
        --gray-500: #6B7280;
        --gray-700: #374151;
        --gray-900: #111827;
      }
      * { box-sizing: border-box; margin: 0; padding: 0; }
      body {
        font-family: 'Inter', -apple-system, sans-serif;
        line-height: 1.6;
        color: var(--gray-700);
        background: var(--gray-50);
        padding: 2rem;
      }
      .report-container {
        max-width: 1200px;
        margin: 0 auto;
        background: white;
        border-radius: 12px;
        box-shadow: 0 4px 6px -1px rgba(0,0,0,0.1);
