      }
      .report-header h1 { font-size: 2.5rem; font-weight: 700; margin-bottom: 0.5rem; }
      .report-header .subtitle { opacity: 0.9; font-size: 1.1rem; }
      .report-content { padding: 2rem 3rem; }
      section { margin-bottom: 3rem; padding-bottom: 2rem; border-bottom: 1px solid var(--gray-200); }
      section:last-child { border-bottom: none; }
      h2 { color: var(--gray-900); font-size: 1.75rem; font-weight: 600; margin-bottom: 1.5rem; padding-bottom: 0.5rem; border-bottom: 3px solid var(--primary); display: inline-block; }
      h3 { color: var(--gray-700); font-size: 1.25rem; font-weight: 600; margin: 1.5rem 0 1rem; }
