      /* Pricing Bands - Colored Bars */
      .band-chart { display: flex; gap: 10px; margin: 20px 0; flex-wrap: wrap; }
      .band {
        flex: 1;
        min-width: 150px;
        padding: 20px 15px;
        border-radius: 8px;
