      /* Opportunity Cards with Priority Colors */
      .opportunity-cards { display: grid; grid-template-columns: repeat(auto-fit, minmax(300px, 1fr)); gap: 20px; margin-top: 20px; }
      .opportunity-card, .rec-card {
        background: white;
        border: 1px solid var(--gray-200);
