      .rec-card.priority-medium { border-left: 4px solid #f39c12; background-color: #fffbf0; }
      .rec-card.priority-low { border-left: 4px solid #3498db; background-color: #f0f7ff; }

      /* Priority Badges */
      .priority {
        display: inline-block;
        margin-top: 10px;
        padding: 4px 12px;
        border-radius: 20px;
        font-size: 0.75rem;
        font-weight: 600;
        text-transform: uppercase;
      }
      .high-priority .priority, .priority-high .priority { background-color: #e74c3c; color: white; }
      .medium-priority .priority, .priority-medium .priority { background-color: #f39c12; color: white; }
      .low-priority .priority, .priority-low .priority { background-color: #3498db; color: white; }

      /* Price Gap Heatmap */
      .heatmap { margin-top: 20px; }
      .gap {
        display: flex;
        justify-content: space-between;
        align-items: center;
        padding: 12px 16px;
        margin: 8px 0;
        border-radius: 6px;
        font-weight: 500;
      }
      .gap span:last-child { font-weight: 600; }
      .gap.hot { background-color: #fde8e8; color: #991b1b; }
      .gap.warm { background-color: #fef3c7; color: #92400e; }
      .gap.moderate { background-color: #fef9c3; color: #854d0e; }
      .gap.cool { background-color: #d1fae5; color: #065f46; }
      .gap.open { background-color: #d1fae5; color: #065f46; }

      /* Recommendation Cards */
      .rec-cards { display: grid; gap: 1rem; margin-top: 1rem; }
      .rec-meta { display: flex; gap: 1rem; align-items: center; margin-top: 1rem; padding-top: 1rem; border-top: 1px solid var(--gray-100); }
      .impact { color: var(--gray-500); font-size: 0.875rem; }

      /* Insights Box */
      .insights, .rationale {
        background-color: var(--gray-50);
        padding: 12px 16px;
        border-radius: 6px;
        margin-top: 12px;
        font-size: 0.9rem;
