      }

      /* Footer */
      .report-footer { background: var(--gray-100); padding: 1.5rem 3rem; text-align: center; font-size: 0.875rem; color: var(--gray-500); }
    </style>
</head>
<body>
  <div class="report-container">
    <header class="report-header">
      <h1>Competitor Analysis Report</h1>
      <p class="subtitle">${category} - Wayfair vs Amazon vs Walmart</p>
    </header>
    <main class="report-content">
      ${execSummary}
      ${scopeHtml}
      ${amazonAnalysis}
      ${comparison}
      ${pricingWhitespace}
      ${recommendations}
      ${supplierIdentification}
    </main>
    <footer class="report-footer">
      <p>Generated on ${new Date().toLocaleDateString('en-US', { year: 'numeric', month: 'long', day: 'numeric' })} | Wayfair Competitive Intelligence</p>
    </footer>
  </div>
</body>
</html>`;

return [{
  json: {
    output: fullHtml,
    sections: {
      scope: !!scopeHtml,
      executive: !!execSummary,
      amazon: !!amazonAnalysis,
      comparison: !!comparison,
      pricing: !!pricingWhitespace,
      recommendations: !!recommendations
    },
    generatedAt: new Date().toISOString()
  }
}];

// === INPUT: Raw LLM output (string) from previous node ===
let html = $input.first().json.output || "";

// 1. Remove Markdown code fences
html = html.replace(/```html|```/g, "").trim();

// 2. Un-escape newlines / tabs / carriage returns and collapse excess whitespace
html = html
  .replace(/\\n/g, "\n")
  .replace(/\\t/g, "\t")
  .replace(/\\r/g, "")
  .replace(/\s{2,}/g, " ")          // multiple spaces → one space
  .replace(/\n\s*\n/g, "\n")        // blank lines → single newline
  .trim();

// 3. Remove any duplicate/malformed wrappers that the LLM might have added
html = html
  .replace(/<\/?(html|body)>/gi, "")   // strip stray <html>/<body>
  .replace(/<!DOCTYPE\s+html?>/gi, "") // strip stray doctype
  .trim();

// 4. Ensure a **single** valid HTML5 skeleton
if (!/<!DOCTYPE\s+html/i.test(html)) {
  html = "<!DOCTYPE html>\n" + html;
}
if (!/<html[\s>]/i.test(html)) {
  html = html.replace(/^/, "<html lang=\"en\">\n");
}
if (!/<body[\s>]/i.test(html)) {
  html = html.replace(/^(.*?)<html[^>]*>/i, "$1<html lang=\"en\"><body>\n");
  html += "\n</body>";
}
if (!/<\/html>/i.test(html)) {
  html += "\n</html>";
}

// 5. Light minify – keep all styles, just remove empty lines between tags
html = html.replace(/>\n\s*</g, "><");

// === OUTPUT: Clean, untouched-style HTML ===
return [{
  json: {
    cleaned_html: html,                     // full readable HTML (preserves all CSS)
    minified_html: html.replace(/\s+/g, " "),// optional one-liner version
    agent_id: 3,
    debug: {
      original_length: ($input.first().json.output || "").length,
      cleaned_length: html.length,
      fences_removed: true,
      wrappers_fixed: true
    }
  }
}];

const text = $input.first().json.minified_html;
const buffer = Buffer.from(text, 'utf8');
const binaryData = {
  data: buffer.toString('base64'),
  mimeType: 'application/octet-stream',
  fileName: 'file.html',
};
items[0].binary = { data: binaryData };
return items;
